import { useTheme } from "next-themes";

export function Logo() {

  const { theme } = useTheme();

  return (
    <div className="flex items-center space-x-2">
      {theme === 'dark' && <img src="/images/logo-dark.png" alt="Logo" className="h-16 w-40" />}
      {theme !== 'dark' && <img src="/images/logo.png" alt="Logo" className="h-16 w-40" />}
    </div>
  );
}
